"use client"
import { useState, useEffect, useRef } from "react";

// ── 使用方式 ──────────────────────────────────────────────
// <LoadingScreen onComplete={() => setReady(true)} />
// onComplete 在動畫結束後呼叫，可用於切換至主畫面
// minDuration: 最少顯示毫秒 (預設 2800)
// ─────────────────────────────────────────────────────────

const LOGO_SRC = "data:image/jpeg;base64,";

export default function LoadingScreen({ onComplete, minDuration = 2800 }) {
  const [phase, setPhase] = useState("enter");   // enter → hold → exit
  const [progress, setProgress] = useState(0);
  const startRef = useRef(null);
  const doneRef = useRef(false);

useEffect(() => {
  startRef.current = Date.now();
}, []);

  // Simulate page load & progress
  useEffect(() => {
    const tick = setInterval(() => {
      setProgress(p => {
        if (p >= 100) { clearInterval(tick); return 100; }
        const elapsed = Date.now() - startRef.current;
        const natural = Math.min(95, (elapsed / (minDuration * 0.85)) * 100);
        return Math.max(p, natural);
      });
    }, 40);

    // Also listen to real window load event
    const finish = () => setProgress(100);
    if (document.readyState === "complete") finish();
    else window.addEventListener("load", finish);

    return () => { clearInterval(tick); window.removeEventListener("load", finish); };
  }, [minDuration]);

  // Orchestrate phases
  useEffect(() => {
    if (progress < 100) return;
    const elapsed = Date.now() - startRef.current;
    const wait = Math.max(0, minDuration - elapsed);
    const t1 = setTimeout(() => setPhase("exit"), wait);
    const t2 = setTimeout(() => {
      if (!doneRef.current) { doneRef.current = true; onComplete?.(); }
    }, wait + 900);
    return () => { clearTimeout(t1); clearTimeout(t2); };
  }, [progress, minDuration, onComplete]);

  const isExit = phase === "exit";

  return (
    <div style={{
      position: "fixed", inset: 0, zIndex: 9999,
      display: "flex", flexDirection: "column",
      alignItems: "center", justifyContent: "center",
      background: "#fff",
      opacity: isExit ? 0 : 1,
      transform: isExit ? "translateY(-24px)" : "translateY(0)",
      transition: "opacity 0.85s cubic-bezier(0.4,0,0.2,1), transform 0.85s cubic-bezier(0.4,0,0.2,1)",
      pointerEvents: isExit ? "none" : "all",
    }}>
      <style>{`
        @keyframes ls-gold-drift {
          0%   { opacity:0; transform:translate(0,0) scale(0.4); }
          40%  { opacity:1; }
          100% { opacity:0; transform:translate(var(--dx),var(--dy)) scale(1.2); }
        }
        @keyframes ls-logo-in {
          0%   { opacity:0; transform:scale(0.7) translateY(18px); }
          100% { opacity:1; transform:scale(1) translateY(0); }
        }
        @keyframes ls-ring-pulse {
          0%,100% { transform:scale(1);   opacity:0.18; }
          50%      { transform:scale(1.08); opacity:0.32; }
        }
        @keyframes ls-bar-shimmer {
          0%   { background-position: -200% center; }
          100% { background-position: 200% center; }
        }
        @keyframes ls-tagline-in {
          0%   { opacity:0; letter-spacing:0.35em; }
          100% { opacity:0.55; letter-spacing:0.22em; }
        }
      `}</style>

      {/* Gold dust particles */}
      {[...Array(22)].map((_, i) => {
        const angle = (i / 22) * Math.PI * 2;
        const r = 80 + (i % 5) * 28;
        return (
          <div key={i} style={{
            position: "absolute",
            width: 3 + (i % 4),
            height: 3 + (i % 4),
            borderRadius: "50%",
            background: `rgba(${i % 2 === 0 ? "212,175,55" : "230,196,96"},0.85)`,
            left: `calc(50% + ${Math.cos(angle) * r}px)`,
            top:  `calc(50% + ${Math.sin(angle) * r * 0.6}px)`,
            "--dx": `${((i * 37 % 60) - 30).toFixed(1)}px`,
            "--dy": `${(-((i * 23 % 50) + 10)).toFixed(1)}px`,
            animation: `ls-gold-drift ${2.4 + (i % 6) * 0.35}s ease-out ${(i * 0.12).toFixed(2)}s infinite`,
          }} />
        );
      })}

      {/* Outer decorative ring */}
      <div style={{
        position: "absolute",
        width: 320, height: 320,
        borderRadius: "50%",
        border: "1px solid rgba(212,175,55,0.2)",
        animation: "ls-ring-pulse 3s ease-in-out infinite",
      }} />
      <div style={{
        position: "absolute",
        width: 260, height: 260,
        borderRadius: "50%",
        border: "1px solid rgba(126,200,227,0.18)",
        animation: "ls-ring-pulse 3s ease-in-out 0.5s infinite",
      }} />

      {/* Logo — no blue background: mix-blend-mode + bg removal via CSS */}
      <div style={{
        width: 180, height: 180,
        borderRadius: "50%",
        overflow: "hidden",
        position: "relative",
        animation: "ls-logo-in 1s cubic-bezier(0.34,1.56,0.64,1) 0.25s both",
        boxShadow: "0 8px 40px rgba(126,200,227,0.18), 0 2px 12px rgba(212,175,55,0.1)",
      }}>
        <img
          src={LOGO_SRC}
          alt="logo"
          style={{
            width: "100%",
            height: "100%",
            objectFit: "cover",
            mixBlendMode: "multiply",
          }}
        />
        {/* Soft white vignette to blend edge */}
        <div style={{
          position: "absolute", inset: 0,
          borderRadius: "50%",
          boxShadow: "inset 0 0 32px 12px rgba(255,255,255,0.9)",
          pointerEvents: "none",
        }} />
      </div>

      {/* Tagline */}
      <p style={{
        marginTop: 28,
        fontFamily: "'DM Serif Display', 'Georgia', serif",
        fontSize: 13,
        color: "#5a7a8a",
        letterSpacing: "0.22em",
        textTransform: "uppercase",
        animation: "ls-tagline-in 1s ease 0.8s both",
      }}>Angela Fei</p>

      {/* Progress bar */}
      <div style={{
        marginTop: 36,
        width: 160,
        height: 2,
        borderRadius: 2,
        background: "rgba(126,200,227,0.15)",
        overflow: "hidden",
        position: "relative",
      }}>
        <div style={{
          height: "100%",
          width: `${progress}%`,
          borderRadius: 2,
          backgroundImage: "linear-gradient(90deg, #a8e4f5 0%, #d4af37 50%, #a8e4f5 100%)",
          backgroundSize: "200% 100%",
          animation: "ls-bar-shimmer 1.8s linear infinite",
          transition: "width 0.4s ease",
        }} />
      </div>

      {/* Percentage */}
      <span style={{
        marginTop: 10,
        fontSize: 11,
        color: "rgba(126,200,227,0.7)",
        fontFamily: "'DM Sans', sans-serif",
        letterSpacing: "0.1em",
        fontWeight: 500,
      }}>{Math.round(progress)}%</span>
    </div>
  );
}
